param([string]$RepoRoot=(Get-Location).Path,[string]$AutoOpsRoot="$env:USERPROFILE\OneDrive\SERA-AutoOps",[string]$PhaseName="s.e.r.a_phase166_unified_phone_json_to_closeout_hardening_v1_overlay",[string]$Branch="work/phase166-unified-phone-json-to-closeout-hardening-v1",[string]$Verifier="scripts\verify-phase166-unified-phone-json-to-closeout-hardening-v1.ps1",[string]$PassHandoffPath="",[string]$MergePendingPath="")
$ErrorActionPreference="Stop"; $Control=Join-Path $AutoOpsRoot "00_control_center"; $Handoff=Join-Path $AutoOpsRoot "06_handoff"; $EvidenceRoot=Join-Path $Control "evidence\phase166-unified-phone-json-to-closeout-hardening-v1"; New-Item -ItemType Directory -Force $Handoff,$EvidenceRoot | Out-Null; Set-Location $RepoRoot
$VerifierPath=Join-Path $RepoRoot $Verifier; if(!(Test-Path $VerifierPath)){throw "Verifier missing: $VerifierPath"}
$VerifyOutput=& powershell -NoProfile -ExecutionPolicy Bypass -File $VerifierPath -RepoRoot $RepoRoot -AutoOpsRoot $AutoOpsRoot 2>&1; $VerifyExit=$LASTEXITCODE; $VerifyText=($VerifyOutput|Out-String); $Stamp=Get-Date -Format "yyyyMMdd_HHmmss"
if($VerifyExit -ne 0){$Blocked=Join-Path $Handoff "$PhaseName-$Stamp-QA_BLOCKED.md"; @("# S.E.R.A. AutoOps Packet","","Status: QA_BLOCKED","Phase: $PhaseName","Branch: $Branch","","## Summary","Phase166 verifier failed.","","## Evidence",$VerifyText) -join "`r`n" | Set-Content $Blocked -Encoding UTF8; Get-Content $Blocked -Raw | Set-Content (Join-Path $Control "CURRENT_CHATGPT_HANDOFF.md") -Encoding UTF8; exit 1}
$EvidencePath=Join-Path $EvidenceRoot "PASS_GUARANTEED-evidence-$Stamp.json"; [ordered]@{status="PASS_GUARANTEED";phase=$PhaseName;branch=$Branch;verifier=$VerifierPath;passHandoffPath=$PassHandoffPath;mergePendingPath=$MergePendingPath;verifierOutput=$VerifyText;createdAtUtc=(Get-Date).ToUniversalTime().ToString("o")} | ConvertTo-Json -Depth 8 | Set-Content $EvidencePath -Encoding UTF8
$Guaranteed=Join-Path $Handoff "$PhaseName-$Stamp-PASS_GUARANTEED.md"; @("# S.E.R.A. AutoOps Packet","","Status: PASS_GUARANTEED","Phase: $PhaseName","Branch: $Branch","","## Summary","Phase166 verifier passed. Unified phone JSON-to-closeout hardening is safe for QA-approved closeout.","","## Evidence",$EvidencePath,"","## Verifier Output",$VerifyText) -join "`r`n" | Set-Content $Guaranteed -Encoding UTF8; Get-Content $Guaranteed -Raw | Set-Content (Join-Path $Control "CURRENT_CHATGPT_HANDOFF.md") -Encoding UTF8; Get-Content $Guaranteed -Raw | Set-Content (Join-Path $Control "CURRENT_CHATGPT_HANDOFF.prompt.md") -Encoding UTF8; Write-Host "PASS_GUARANTEED: $Guaranteed"; exit 0
